Here's the complete implementation of the functions using the Hexi library:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket packet;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read packet_id
    stream >> packet.packet_id;

    // Read username with length prefix
    stream >> hexi::prefixed(packet.username);

    // Read scores vector (count + elements)
    stream >> packet.scores;

    // Read metadata as null-terminated string for zero-copy
    stream >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes by seeking to the end
    adaptor.seek_read(adaptor.size());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use span() for zero-copy view of packet_id (first 4 bytes)
    auto packet_id_span = buffer.subspan(0, sizeof(uint32_t));
    info.packet_id = *reinterpret_cast<const uint32_t*>(packet_id_span.data());

    // Advance stream past packet_id since we already read it via span
    stream.advance_read(sizeof(uint32_t));

    // Read username using prefixed adaptor to get string_view
    std::string_view username_view;
    stream >> hexi::prefixed(username_view);
    info.username = username_view;

    // Skip scores vector: read count first
    uint32_t score_count;
    stream >> score_count;

    // Skip the actual score data
    stream.advance_read(score_count * sizeof(uint32_t));

    return info;
}
```

