Looking at the code fragments and understanding the Hexi library's approach to zero-copy operations, here's the complete implementation:

```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>
#include <algorithm>

struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor from the span for zero-copy operations
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary stream to read from the adaptor
    hexi::binary_stream stream(adaptor);

    PacketHeader header;

    // Read the header fields using zero-copy operations
    stream >> header.version >> header.flags >> header.packet_id;

    return header;
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor from the span
    hexi::buffer_adaptor adaptor(buffer);

    // Get a view of the available data for zero-copy string extraction
    auto data_view = adaptor.view();

    // Find the null terminator (delimiter)
    auto null_pos = std::find(data_view.begin(), data_view.end(), '\0');

    if (null_pos != data_view.end()) {
        // Calculate the length of the string (excluding the null terminator)
        size_t length = std::distance(data_view.begin(), null_pos);

        // Create a string_view from the character data
        // reinterpret_cast is safe here since we're viewing the same underlying bytes
        return std::string_view(reinterpret_cast<const char*>(data_view.data()), length);
    }

    // If no null terminator found, return empty string_view
    return std::string_view();
}
```

