#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Create a read-only span from the source buffer
    std::span<const uint8_t> source_span(source_buffer);

    // Create buffer adaptor for reading
    hexi::buffer_adaptor adaptor(source_span);

    // Create binary stream for reading operations
    hexi::binary_stream stream(adaptor);

    // Create destination vector with the requested size
    std::vector<uint8_t> result(bytes_to_read);

    // Read the specified number of bytes
    stream.read(result.data(), bytes_to_read);

    return result;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Create a writable span from the destination buffer
    std::span<uint8_t> dest_span(dest_buffer);

    // Create buffer adaptor for writing
    hexi::buffer_adaptor adaptor(dest_span);

    // Create binary stream for writing operations
    hexi::binary_stream stream(adaptor);

    // Write the source data to the destination buffer
    stream.write(source_data.data(), source_data.size());

    // Update the destination buffer size to match what was written
    adaptor.advance_write(source_data.size());
}
```

