    std::vector<uint8_t> buffer = {1, 2, 3, 4, 5, 6, 7, 8};

    auto peeked = peek_buffer_data(buffer, 3);

    EXPECT_EQ(3, peeked.size());
    EXPECT_EQ(1, peeked[0]);
