    std::vector<uint8_t> buffer = {10, 20, 30, 40};

    auto first_peek = peek_buffer_data(buffer, 2);
    auto second_peek = peek_buffer_data(buffer, 2);

    EXPECT_EQ(first_peek, second_peek);
    EXPECT_EQ(10, first_peek[0]);
    EXPECT_EQ(20, first_peek[1]);
