#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result{};

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Preview the first byte (data_type) without advancing the read pointer
    // We need to check if there's at least 1 byte available
    if (buffer.size() < 1) {
        return result; // Not enough data for even the data_type
    }

    // Peek at the data_type without consuming it
    // Since Hexi doesn't have a direct peek function, we'll read and then rewind
    auto start_pos = stream.tell(); // Get current position

    // Read data_type
    stream >> result.data_type;

    // Check if we have enough data for the header (data_type + item_count)
    if (buffer.size() < 5) { // 1 byte for data_type + 4 bytes for uint32_t
        return result; // Not enough data for complete header
    }

    // Read item_count
    uint32_t item_count;
    stream >> item_count;

    // Calculate required data size: header (5 bytes) + items (item_count * 4 bytes)
    size_t required_size = 5 + item_count * 4;
    if (buffer.size() < required_size) {
        return result; // Not enough data for all items
    }

    // Reset stream to beginning and read complete data
    stream.seek(start_pos);

    // Read header again (now we'll consume it)
    stream >> result.data_type >> item_count;

    // Read items based on data_type
    if (result.data_type == 0) {
        // Integers
        result.int_items.reserve(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            uint32_t value;
            stream >> value;
            result.int_items.push_back(value);
        }
    } else if (result.data_type == 1) {
        // Floats
        result.float_items.reserve(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            float value;
            stream >> value;
            result.float_items.push_back(value);
        }
    }
    // If data_type is not 0 or 1, we'll return empty result

    return result;
}
