```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor from the span
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream with the adaptor
    hexi::binary_stream stream(adaptor);

    // Check available data - header size is 8 bytes (4 + 2 + 2)
    if (adaptor.available() < sizeof(PacketHeader)) {
        throw std::runtime_error("Not enough data for packet header");
    }

    // Get the read pointer using buffer_adaptor's pointer methods
    const uint8_t* read_ptr = adaptor.read_pointer();

    // Get a zero-copy view of the header using binary_stream's span operations
    auto header_span = stream.get_span(sizeof(PacketHeader));

    // Reinterpret the span data as PacketHeader (zero-copy view)
    const PacketHeader* header_view = reinterpret_cast<const PacketHeader*>(header_span.data());

    // Return a copy of the header data
    return *header_view;
}
```

