    uint32_t header = 12345;
    std::vector<uint8_t> data = {1, 2, 3, 4, 5};

    write_to_dynamic_buffer(buffer, header, data);

    auto result = read_from_dynamic_buffer(buffer, data.size());

    EXPECT_EQ(12345, result.header);
    EXPECT_EQ(data, result.data);
}

TEST(DynamicBuffer, WriteLargeData) {
    hexi::dynamic_buffer<static_cast<size_t>(1024)> buffer;
    uint32_t header = 999;
    std::vector<uint8_t> data(2000, 0xAA);

    write_to_dynamic_buffer(buffer, header, data);

    auto result = read_from_dynamic_buffer(buffer, data.size());

    EXPECT_EQ(999, result.header);
    EXPECT_EQ(data, result.data);
}

TEST(DynamicBuffer, WriteEmptyData) {
    hexi::dynamic_buffer<static_cast<size_t>(1024)> buffer;
    uint32_t header = 777;
    std::vector<uint8_t> data;

    write_to_dynamic_buffer(buffer, header, data);

    auto result = read_from_dynamic_buffer(buffer, 0);

    EXPECT_EQ(777, result.header);
    EXPECT_TRUE(result.data.empty());
}

