#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Create a file buffer for the specified file
    hexi::file_buffer file(file_path.string().c_str());

    // Create a buffer to store the header data
    std::vector<uint8_t> header(header_size);

    // Read the header data from the file
    // The file_buffer will read from the current position (start of file)
    // and advance its internal read pointer, but since we're creating a new
    // file_buffer instance just for this preview, the original file's read
    // position remains unaffected
    size_t bytes_read = file.read(reinterpret_cast<char*>(header.data()), header_size);

    // Resize the vector to the actual number of bytes read
    // (in case the file is smaller than the requested header_size)
    header.resize(bytes_read);

    return header;
}
```

