    const void* read_ptr;
    bool is_empty;
};

BufferState get_buffer_state(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    BufferState state;
    state.size = buffer.size();           // Get current buffer size
    state.read_ptr = &buffer[0];          // Get current read pointer
    state.is_empty = buffer.empty();      // Check if buffer is empty
    return state;
}

