std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor for writing
    hexi::pmc::buffer_write_adaptor write_adaptor(buffer);

    // Check available space before writing
    if (write_adaptor.free() >= input_data.size()) {
        // Write data to the buffer
        write_adaptor.write(input_data.data(), input_data.size());
    }

    // Create buffer_read_adaptor for reading
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer);

    // Check readable size
    std::vector<uint8_t> output_data;
    if (read_adaptor.size() > 0) {
        output_data.resize(read_adaptor.size());
        // Read data back from the buffer
        read_adaptor.read(output_data.data(), output_data.size());
    }

    return output_data;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create buffer_read_adaptor for the provided buffer data
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer_data);

    std::vector<uint8_t> peeked_data;

    // Ensure we don't try to peek more than available
    std::size_t actual_peek_size = std::min(peek_size, read_adaptor.size());

    if (actual_peek_size > 0) {
        // Get pointer to current read position
        const uint8_t* read_ptr = read_adaptor.read_ptr();

        // Use copy() to peek at data without moving read cursor
        peeked_data.resize(actual_peek_size);
        read_adaptor.copy(peeked_data.data(), actual_peek_size);

        // Now actually consume the data using read()
        read_adaptor.read(nullptr, actual_peek_size); // We already have the data, so we can pass nullptr
    }

    return peeked_data;
}
