struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create a buffer adaptor from the input buffer
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Verify we have enough data for the header
    if (adaptor.size() < sizeof(Header)) {
        throw std::runtime_error("Buffer too small for header");
    }

    // Use copy() to peek at header without advancing read cursor
    Header header;
    adaptor.copy(&header, sizeof(Header));

    // Use read_ptr() to verify pointer position hasn't changed
    const std::byte* ptr = adaptor.read_ptr();
    if (ptr != reinterpret_cast<const std::byte*>(buffer.data())) {
        throw std::runtime_error("Read cursor advanced unexpectedly");
    }

    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    // Create a buffer adaptor from the input buffer
    hexi::pmc::buffer_adaptor adaptor(buffer);

    if (adaptor.empty()) {
        return {}; // Empty buffer, return empty result
    }

    // Use copy() to peek at first byte
    uint8_t first_byte;
    adaptor.copy(&first_byte, 1);

    // Based on the peeked value, decide whether to read more data
    std::vector<uint8_t> result;

    // Example condition: if first byte is non-zero, read the entire buffer
    if (first_byte != 0) {
        // Use read() to consume data only if needed
        result.resize(adaptor.size());
        adaptor.read(result.data(), result.size());
    }
    // Alternative condition example: if first byte matches a specific pattern
    else if (first_byte == 0xAA) {
        // Read only a specific amount based on condition
        const size_t bytes_to_read = 4;
        if (adaptor.size() >= bytes_to_read) {
            result.resize(bytes_to_read);
            adaptor.read(result.data(), bytes_to_read);
        }
    }

    return result;
}
