```cpp
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Write sensor_id directly (no endian conversion needed for uint32_t)
        adaptor(sensor_id);

        // Write temperatures array size first
        uint32_t temp_size = static_cast<uint32_t>(temperatures.size());
        adaptor(temp_size);

        // Convert and write each temperature value
        for (const auto& temp : temperatures) {
            float le_temp = hexi::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor.write(le_temp);
        }

        // Convert and write pressure
        double le_pressure = hexi::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor.write(le_pressure);
    }

    void serialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor(sensor_id);

        // Read temperatures array size
        uint32_t temp_size;
        adaptor(temp_size);

        // Resize vector and read temperatures
        temperatures.resize(temp_size);
        for (auto& temp : temperatures) {
            adaptor.read(temp);
            hexi::little_to_native_inplace(temp);
        }

        // Read and convert pressure
        adaptor.read(pressure);
        hexi::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream.serialise(data);
    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    MeasurementData data;
    stream.serialise(data);
    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    SensorInfo info;

    // Extract sensor name if present (null-terminated string)
    info.sensor_name = stream.view();

    // Check bounds before reading sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    stream.read(info.sensor_id);

    // Skip remaining data
    stream.skip(adaptor.remaining());

    return info;
}
